Bash(NEXT_PUBLIC_SUPABASE_URL=https://dsjjdnfzibjflwoivlxq.supabase.co NEXT_PUBLIC_SUPABASE_ANON_KEY=sb_publishable_J6Ot7y_mT0nINx1T90-bww_94pM0JM3 node -e "
const { createClient } = require\('@supabase/supabase-js'\);
const supabase = createClient\(process.env.NEXT_PUBLIC_SUPABASE_URL, process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY\);

async function run\(\) {
  // Find channels that are pending but have a reviewed_at \(meaning they were already decided on\)
  const { data: wronglyRescued, error } = await supabase
    .from\('curator_channels'\)
    .select\('channel_id, name, reviewed_at'\)
    .eq\('status', 'pending'\)
    .not\('reviewed_at', 'is', null\);

  if \(error\) { console.error\(error\); return; }
  console.log\('Wrongly rescued channels \(pending but already reviewed\):', wronglyRescued.length\);
  if \(wronglyRescued.length > 0\) {
    console.log\('Sample:', wronglyRescued.slice\(0, 5\).map\(c => c.name\)\);
  }

  // Move them back to rejected
  if \(wronglyRescued.length > 0\) {
    const ids = wronglyRescued.map\(c => c.channel_id\);
    const { error: updateError } = await supabase
      .from\('curator_channels'\)
      .update\({ status: 'rejected' }\)
      .in\('channel_id', ids\);

    if \(updateError\) console.error\('Update error:', updateError\);
    else console.log\('Moved', ids.length, 'channels back to rejected'\);
  }

  // Check final counts
  const { count: pending } = await supabase.from\('curator_channels'\).select\('*', { count: 'exact', head: true }\).eq\('status', 'pending'\);
  const { count: rejected } = await supabase.from\('curator_channels'\).select\('*', { count: 'exact', head: true }\).eq\('status', 'rejected'\);
  const { count: approved } = await supabase.from\('curator_channels'\).select\('*', { count: 'exact', head: true }\).eq\('status', 'approved'\);
  const { count: filtered } = await supabase.from\('curator_channels'\).select\('*', { count: 'exact', head: true }\).eq\('status', 'filtered'\);
  const { count: total } = await supabase.from\('curator_channels'\).select\('*', { count: 'exact', head: true }\);

  console.log\('\\\\nFinal counts:'\);
  console.log\('Total:', total\);
  console.log\('Approved:', approved\);
  console.log\('Rejected:', rejected\);
  console.log\('Pending:', pending\);
  console.log\('Filtered:', filtered\);
  console.log\('Review \(pending+filtered\):', \(pending||0\) + \(filtered||0\)\);
}
run\(\);
